INSERT INTO `conversation_messages` VALUES (460, 99, 14, 'assistant', '当然可以！你可以告诉我你感兴趣的具体话题。比如：\n\n1. **旅行目的地**：你想去哪里旅行？我可以提供景点推荐、当地文化介绍和美食建议。\n2. **行程规划**：如果你已经有具体的旅行计划，我可以帮你优化行程，提供交通和住宿的建议。\n3. **美食推荐**：你喜欢吃什么类型的美食？我可以推荐一些当地的特色美食和餐厅。\n4. **闲聊**：如果你想聊点别的，比如电影、音乐或者其他兴趣爱好，我也很乐意陪你聊天。\n\n你有什么具体的想法或问题吗？', NULL, NULL, '2025-07-21 18:17:54', 12, NULL, NULL, NULL);
