INSERT INTO `conversation_messages` VALUES (566, 103, 14, 'user', '我想去安徽玩', NULL, NULL, '2025-07-21 23:22:17', 135, NULL, NULL, NULL);
INSERT INTO `conversation_messages` VALUES (567, 103, 14, 'assistant', '好的，去安徽旅行是个不错的选择！这里有几个推荐的地方：\n\n1. **黄山**：黄山以奇松、怪石、云海、温泉著称，是中国最著名的山脉之一。你可以考虑在山上住一晚，看看日出和日落。\n\n2. **宏村**：宏村是徽派建筑的代表，古朴的村落和美丽的水系非常有特色。适合喜欢摄影和文化探索的朋友。\n\n3. **西递**：与宏村类似，西递也是一个保存完好的古村落，但风格略有不同，值得一游。\n\n4. **九华山**：九华山是佛教圣地，有很多古老的寺庙和优美的自然风光，适合心灵之旅。\n\n5. **太平湖**：如果你喜欢水上活动或者想找个安静的地方放松一下，太平湖是个', NULL, NULL, '2025-07-21 23:22:26', 136, NULL, NULL, NULL);
