INSERT INTO `conversation_messages` VALUES (648, 103, 14, 'assistant', '北京是个充满历史和现代魅力的城市，有很多值得一看的地方！你可以去故宫感受皇家的气派，爬长城体验“不到长城非好汉”的豪情，还可以去颐和园、天坛逛逛。如果你对现代文化感兴趣，可以去798艺术区看看当代艺术，或者去三里屯感受一下北京的夜生活。\n\n你大概计划什么时候去？有几天的时间呢？这样我可以帮你规划一下行程。', NULL, NULL, '2025-07-22 13:47:21', 239, NULL, NULL, NULL);
