INSERT INTO `conversation_messages` VALUES (731, 104, 14, 'user', '我想去上海玩', NULL, NULL, '2025-07-22 17:01:30', 86, NULL, NULL, NULL);
INSERT INTO `conversation_messages` VALUES (732, 104, 14, 'assistant', '太棒了！上海是一个非常有魅力的城市，有很多好玩的地方和美食。你有什么特别想看的景点或者想尝试的活动吗？我可以帮你规划一下行程，推荐一些必去的地方和好吃的餐厅哦！\n\n比如：\n- **外滩**：欣赏美丽的夜景和历史悠久的建筑。\n- **东方明珠塔**：俯瞰整个上海的美景。\n- **豫园**：感受古典园林的魅力。\n- **田子坊**：逛逛文艺的小店和咖啡馆。\n- **南京路步行街**：购物和品尝各种小吃。\n\n你对这些地方感兴趣吗？还是有其他特别的需求？', NULL, NULL, '2025-07-22 17:01:40', 88, NULL, NULL, NULL);
