INSERT INTO `conversation_messages` VALUES (827, 106, 14, 'assistant', '# 南京文化探索之旅\n## 1. 方案特色\n本方案以南京的历史文化和古迹为主线，适合对历史文化感兴趣的游客。行程中将参观多个具有代表性的历史遗迹和博物馆，感受南京深厚的文化底蕴。\n\n## 2. 每日详细安排\n### 第1天：2025-07-23\n- **上午**\n  - **08:00-09:00**：早餐\n    - **餐厅名称**：金陵饭店（评分4.5/5，人均60元）\n    - **推荐菜品**：金陵小笼包、鸭血粉丝汤\n    - **地址**：南京市秦淮区汉中路2号\n    - **交通**：步行约5分钟\n\n  - **09:00-11:00**：游览明孝陵\n    - **地址**：南京市玄武区紫金山南麓\n    - **交通**：打车约20分钟，约30元，经中山南路、中山门大街\n    - **景点介绍**：明孝陵是明朝开国皇帝朱元璋的陵墓，是中国古代最大的帝王陵寝之一。\n    - **备注**：建议穿着舒适的鞋子，注意防晒。\n\n- **中午**\n  - **11:00-12:30**：午餐\n    - **餐厅名称**：南京大牌档（评分4.7/5，人均80元）\n    - **推荐菜品**：盐水鸭、糖醋排骨\n    - **地址**：南京市秦淮区夫子庙贡院街10号\n    - **交通**：打车约15分钟，约20元，经中山门大街、龙蟠中路\n\n- **下午**\n  - **13:00-15:00**：参观南京博物院\n    - **地址**：南京市玄武区中山东路321号\n', NULL, NULL, '2025-07-23 10:05:25', 14, NULL, NULL, NULL);
