INSERT INTO `conversation_messages` VALUES (844, 106, 14, 'assistant', '# 南京文化探索之旅\n## 1. 方案特色\n本方案以南京的历史文化和古迹为主线，适合喜欢深入了解城市历史和文化的旅行者。行程中包含多个著名的历史景点，如中山陵、明孝陵等。\n\n## 2. 每日详细安排\n- **第1天：2025-07-23**\n  - **上午**\n    - **8:00-9:00**：早餐\n      - **餐饮推荐**：秦淮人家（评分4.5/5，人均30元）\n      - **地址**：南京市秦淮区夫子庙步行街\n      - **交通**：打车（从酒店到餐厅），约15分钟，费用约20元\n    - **9:00-11:00**：参观中山陵\n      - **景点介绍**：中国近代伟大的民主革命先行者孙中山先生的陵墓\n      - **地址**：南京市玄武区紫金山南麓\n      - **交通**：公交34路（从夫子庙到中山陵），约40分钟，票价2元\n  - **中午**\n    - **11:30-13:00**：午餐\n      - **餐饮推荐**：狮子楼（评分4.6/5，人均60元）\n      - **地址**：南京市玄武区太平门大街\n      - **交通**：打车（从中山陵到狮子楼），约15分钟，费用约20元\n  - **下午**\n    - **13:30-15:30**：参观明孝陵\n      - **景点介绍**：明朝开国皇帝朱元璋及其皇后的陵寝\n      - **地址**：南京市玄武区钟山风景区内\n      - **交通**：公交34路（从狮子楼到明孝陵），约30分钟，票价2元\n    - **16:00-17:30**：游览夫子庙\n      - **景点介绍**：南京最著名的文化商业街区之一\n      - **地址**：南京市秦淮区夫子庙步行街\n      - **交通**：地铁3号线（从明孝陵到夫子庙），约30分钟，票价4元\n  - **晚上**\n    - **18:00-19:30**：晚餐\n      - **餐饮推荐**：金陵饭店（评分4.7/5，人均100元）\n', NULL, NULL, '2025-07-23 10:43:42', 33, NULL, NULL, NULL);
