INSERT INTO `conversation_messages` VALUES (875, 111, 15, 'assistant', '青岛真是个好地方！那边的海边风景特别美，还有很多好吃的海鲜。你打算什么时候去呢？是想在那边待几天？这样我可以帮你规划一下行程，比如哪些景点值得一去，哪里可以尝到地道的美食。', NULL, NULL, '2025-07-23 13:01:19', 27, NULL, NULL, NULL);
