INSERT INTO `conversation_messages` VALUES (912, 120, 18, 'assistant', '# 南京文化探索之旅\n## 1. 方案特色\n本方案以南京的历史文化和古迹为主要探索内容，适合对历史文化感兴趣的旅行者。行程中将参观多个著名的历史景点，深入了解南京的过去和现在。\n\n## 2. 每日详细安排\n- **第1天：2025-07-23**\n  - **上午**\n    - **8:00-9:00**：早餐\n      - 餐厅名称：金陵饭店（评分4.5/5，人均50元）\n      - 推荐菜品：鸭血粉丝汤、小笼包\n      - 地址：南京市玄武区中山路168号\n      - 交通：步行至酒店餐厅\n    - **9:00-11:00**：游览明孝陵\n      - 地址：南京市玄武区紫金山南麓\n      - 交通：打车（从酒店到明孝陵），约20分钟，费用约30元\n      - 景点介绍：明孝陵是明朝开国皇帝朱元璋及其皇后的陵墓，是中国古代最大的帝王陵寝之一\n      - 备注：建议提前预订门票，注意防晒和补水\n\n  - **中午**\n    - **11:00-12:00**：午餐\n      - 餐厅名称：老门东小吃街（评分4.0/5，人均30元）\n      - 推荐菜品：盐水鸭、牛肉锅贴\n', NULL, NULL, '2025-07-23 19:16:50', 8, NULL, NULL, NULL);
