INSERT INTO `conversation_messages` VALUES (999, 126, 18, 'user', '请介绍一下天津', NULL, NULL, '2025-07-23 22:46:38', 1, NULL, NULL, NULL);
INSERT INTO `conversation_messages` VALUES (1000, 126, 18, 'assistant', '天津，这座美丽的城市位于中国北方，紧邻北京，是中国的四大直辖市之一。它不仅有着悠久的历史文化，还融合了现代都市的气息。天津的建筑风格多样，从古色古香的传统建筑到充满异国情调的小洋楼，再到现代化的高楼大厦，每一处都展现着这座城市独特的魅力。\n\n- **必游景点**：意式风情区、五大道、古文化街（南市食品街）、天津之眼摩天轮等。\n- **美食推荐**：狗不理包子、耳朵眼炸糕、十八街麻花、锅巴菜等地道小吃绝对值得一试。\n- **当地文化**：天津相声闻名遐迩，如果有机会的话一定要去听听现场表演；此外，杨柳青年画也是天津非物质文化遗产中的瑰宝之一。\n- **交通贴士**：天津拥有发达的公共交通系统，地铁覆盖了主要区域，出行非常方便。从北京出发，乘坐高铁最快仅需半小时左右即可到达。\n\n天津是一座非常适合漫步探索的城市，无论是历史文化爱好者还是美食家，在这里都能找到属于自己的乐趣。如果你计划来天津旅行，不妨提前规划一下行程哦！有什么特别想了解的地方或活动吗？', NULL, NULL, '2025-07-23 22:46:57', 3, NULL, NULL, NULL);
